parameters.functionCode:
// Extract magic content request
return {
  phone: $input.first().json.phone || $input.first().json.body.phone,
  userId: $input.first().json.userId || $input.first().json.body.userId,
  sessionId: $input.first().json.sessionId || $input.first().json.body.sessionId,
  occasion: $input.first().json.occasion || $input.first().json.body.occasion || 'honeymoon',
  reservationId: $input.first().json.reservationId || $input.first().json.body.reservationId,
  timestamp: new Date().toISOString()
};

// Check if user opted in
const optInStatus = $input.first().json.opt_in_magic;

if (!optInStatus) {
  return {
    allowed: false,
    message: 'Magic content is not enabled for your profile. Visit your settings to opt in!',
    error: 'user_not_opted_in'
  };
}

return {
  allowed: true,
  message: 'User opted in, proceeding with generation',
  error: null
};

// Format content URLs for WhatsApp
const content = $input.first().json;

let reply = `✨ Your magical ${content.occasion} content is ready!\n\n`;

if (content.playlist_url) {
  reply += `🎵 Playlist: ${content.playlist_url}\n`;
}
if (content.video_url) {
  reply += `🎬 Video: ${content.video_url}\n`;
}
if (content.song_credits) {
  reply += `\n🎼 Artists: ${content.song_credits.join(', ')}\n`;
}

reply += `\nEnjoy your magical moments! ✨`;

return {
  message: reply,
  playlist: content.playlist_url,
  video: content.video_url,
  timestamp: new Date().toISOString()
};

nodes.parameters:
id": "send-content",
      "name": "Send Content via WhatsApp",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1450, 100],
      "notes": "Send generated content URLs to guest"
    },
    {
      "parameters": {
        "operation": "insert",
        "schema": "public",
        "table": "magic_content",
        "columns": "reservation_id,user_id,occasion,playlist_url,video_url,created_at",
        "dataToSend": "{
          \"reservation_id\": \"{{ $node[\"extract-request\"].json.reservationId }}\",
          \"user_id\": \"{{ $node[\"extract-request\"].json.userId }}\",
          \"occasion\": \"{{ $node[\"extract-request\"].json.occasion }}\",
          \"playlist_url\": \"{{ $node[\"format-reply\"].json.playlist }}\",
          \"video_url\": \"{{ $node[\"format-reply\"].json.video }}\",
          \"created_at\": \"{{ $node[\"extract-request\"].json.timestamp }}\"
        }"
      },
      "id": "save-content",
      "name": "Save to Magic Content",
      "type": "n8n-nodes-base.supabase",
      "typeVersion": 1,
      "position": [1450, 250],
      "notes": "Store generated content metadata"
    },
    {
      "parameters": {
        "operation": "insert",
        "schema": "public",
        "table": "whatsapp_messages",
        "columns": "session_id,user_id,phone_number,direction,body,created_at",
        "dataToSend": "{
          \"session_id\": \"{{ $node[\"extract-request\"].json.sessionId }}\",
          \"user_id\": \"{{ $node[\"extract-request\"].json.userId }}\",
          \"phone_number\": \"{{ $node[\"extract-request\"].json.phone }}\",
          \"direction\": \"outbound\",
          \"body\": \"{{ $node[\"format-reply\"].json.message }}\",
          \"created_at\": \"{{ $node[\"extract-request\"].json.timestamp }}\"
        }"
      },
      "id": "log-message",
      "name": "Log Message",
      "type": "n8n-nodes-base.supabase",
      "typeVersion": 1,
      "position": [1450, 400],
      "notes": "Audit log of magic content sent"
    },
    {
      "parameters": {
        "functionCode": "// Send error message to user\nreturn {\n  phone: $input.first().json.phone,\n  message: \"Unable to process your magic content request. Please try again or contact support.\",\n  error: true\n};"
      },
      "id": "handle-error",
      "name": "Handle Error",
      "type": "n8n-nodes-base.function",
      "typeVersion": 1,
      "position": [1050, 300],
      "notes": "Error handling for content generation failures"
    },
    {
      "parameters": {
        "url": "=https://api.twilio.com/2010-04-01/Accounts/{{ $env.TWILIO_ACCOUNT_SID }}/Messages",
        "authentication": "predefinedCredentialType",
        "nodeCredentialType": "twilioApi",
        "method": "POST",
        "bodyParametersJson": "{\n  \"From\": \"whatsapp:+13369996930\",\n  \"To\": \"whatsapp:{{ $node[\"handle-error\"].json.phone }}\",\n  \"Body\": \"{{ $node[\"handle-error\"].json.message }}\"\n}",
        "options": {
          "timeout": 10000
        }
      },
      "id": "send-error-message",
      "name": "Send Error Message",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4,
      "position": [1250, 300],
      "notes": "Notify user of generation failure"
    }
  ],
  "connections": {
